noncompliant:
// Forward declaration only
class Body;

class Handle {
public:
    Handle();
    ~Handle() {
        delete impl; // Noncompliant - Body is incomplete
    }
private:
    Body* impl;
};

// Another example with incomplete type
class ForwardDeclared;

void cleanup(ForwardDeclared* ptr) {
    delete ptr; // Noncompliant - ForwardDeclared is incomplete
}

compliant:
// Complete definition available
class Body {
public:
    ~Body() {}
    // class implementation
};

class Handle {
public:
    Handle();
    ~Handle() {
        delete impl; // Compliant - Body is complete
    }
private:
    Body* impl;
};

// Use smart pointers for automatic cleanup
#include <memory>

class Body; // Forward declaration

class Handle {
public:
    Handle();
    ~Handle() = default; // Compliant - no explicit delete
private:
    std::unique_ptr<Body> impl; // Smart pointer handles deletion
};
